import {
  workflow,
  trigger,
  node,
} from '@n8n/workflow-sdk';

const manualTrigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' },
});

const approvalTest = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: {
    name: 'approval test',
    parameters: {
      mode: 'manual',
      fields: {
        values: [
          {
            name: 'status',
            type: 'stringValue',
            string: 'approved',
          },
        ],
      },
    },
  },
});

export default workflow('approval-test', 'Approval Test Workflow')
  .add(manualTrigger)
  .to(approvalTest);
